551:     /**
552:      * Wait for a controller to mark all the brokers as ready (registered and unfenced).
553:      * And also wait for the metadata cache up-to-date in each broker server.
554:      */
555:     public void waitForReadyBrokers() throws ExecutionException, InterruptedException {
556:         // We can choose any controller, not just the active controller.
557:         // If we choose a standby controller, we will wait slightly longer.
558:         ControllerServer controllerServer = controllers.values().iterator().next();
559:         Controller controller = controllerServer.controller();
560:         controller.waitForReadyBrokers(brokers.size()).get();
561: 
562:         // make sure metadata cache in each broker server is up-to-date
563:         TestUtils.waitForCondition(() ->
564:                 brokers.values().stream().map(BrokerServer::metadataCache)
565:                     .allMatch(cache -> brokers.values().stream().map(b -> b.config().brokerId()).allMatch(cache::hasAliveBroker)),
566:             "Failed to wait for publisher to publish the metadata update to each broker.");
567:     }
